import{_ as s,o as t,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"RPI Wireless Hotspot","description":"Notes on RPI Wireless Hotspot.","frontmatter":{"title":"RPI Wireless Hotspot","description":"Notes on RPI Wireless Hotspot."},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/rpi-wireless-hotspot.md","filePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/rpi-wireless-hotspot.md"}'),r={name:"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/rpi-wireless-hotspot.md"};function o(l,e,n,p,h,d){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="rpi-wireless-hotspot" tabindex="-1">RPI Wireless Hotspot <a class="header-anchor" href="#rpi-wireless-hotspot" aria-label="Permalink to &quot;RPI Wireless Hotspot&quot;">​</a></h1><p>Configures a Raspberry Pi (built-in or USB WiFi) as a WPA-encrypted hotspot that shares an Ethernet WAN — useful in hotels, dorms, or when you do not want a separate router.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://github.com/harryallerston/RPI-Wireless-Hotspot" target="_blank" rel="noreferrer">harryallerston/RPI-Wireless-Hotspot</a></li></ul><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li>Hotspot starts on boot</li><li>WPA encryption (default SSID <code>RaspberryPiFi</code>, key <code>0123456789A</code> — change during install)</li><li>Pi keeps normal LAN behavior on Ethernet</li><li>Optional custom DNS (including unblock-us presets)</li><li>Chromecast-friendly DNS interception when using unblock-us</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>Raspberry Pi B series or Pi 3+</li><li>WiFi adapter with <strong>nl80211</strong> / hostapd support (most modern adapters)</li><li>Active Ethernet uplink</li></ul><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/harryallerston/RPI-Wireless-Hotspot.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RPI-Wireless-Hotspot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install</span></span></code></pre></div><p>Follow prompts for DNS and Chromecast options. Existing configs are backed up with <code>.old</code> suffix.</p><h2 id="configuration-notes" tabindex="-1">Configuration notes <a class="header-anchor" href="#configuration-notes" aria-label="Permalink to &quot;Configuration notes&quot;">​</a></h2><ul><li>WiFi channel: <code>/etc/hostapd/hostapd.conf</code></li><li>Tested on fresh Raspbian; existing installs may need manual merge</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">Raspberry Pi Hotspot</a></li></ul>`,15)])])}const b=s(r,[["render",o]]);export{u as __pageData,b as default};
